mapper.update:
update users
	set last_login_at = sysdate
where user_code = #{userCode}

update users
set password_hash = #{passwordHash}
   ,email = #{email}
   ,phone = #{phone}
   ,first_login_yn = 'N'
where user_code = #{userCode}

UPDATE user_auto_login
SET last_used_at = SYSDATE
WHERE token_hash = #{tokenHash}
